     3→// Lazy initialization to avoid build-time errors when env vars aren't set
     4→let _stripe: Stripe | null = null;
     5→
     6→function getStripe(): Stripe {
     7→  if (!_stripe) {
     8→    const key = process.env.STRIPE_SECRET_KEY;
     9→    if (!key) {
    10→      throw new Error('STRIPE_SECRET_KEY is not defined');
    11→    }
    12→    _stripe = new Stripe(key, {
    13→      apiVersion: '2024-04-10',
    14→      typescript: true,
    15→    });
    16→  }
    17→  return _stripe;
    18→}
    19→
    20→// Proxy to lazily initialize Stripe
    21→export const stripe = new Proxy({} as Stripe, {
    22→  get(_target, prop: keyof Stripe) {
    23→    return getStripe()[prop];
    24→  }
    25→});
